	UPDATE stock
    SET
        stock_avail_qty = stock_avail_qty - #{reqQty},
        stock_reserve_qty = stock_reserve_qty + #{reqQty}
    WHERE stock_id = #{stockId}
      AND stock_avail_qty >= #{reqQty}

UPDATE stock
SET
    stock_prev_qty = stock_prev_qty - #{usedQty},
    stock_reserve_qty = stock_reserve_qty - #{reqQty},
    stock_avail_qty = stock_avail_qty + #{returnQty}
WHERE stock_id = #{stockId}
  AND stock_prev_qty >= #{usedQty}
  AND stock_reserve_qty >= #{reqQty}

UPDATE STOCK
SET STOCK_PREV_QTY = STOCK_PREV_QTY + #{workPrevQty}
WHERE STOCK_ITEM = #{workItem}
